/**
 * Compares two fragments A and B to determine their optimal ordering.
 * A comes before B if concatenating A followed by B (AB) results in a lexicographically larger binary string than BA.
 * This is achieved by prioritizing more ones, and if ones are equal, prioritizing fewer zeros.
 * @returns A negative number if A comes before B, a positive number if B comes before A, and 0 if they are equivalent.
 */
function compareFragments(A: Fragment, B: Fragment): number {
    // 1. Prioritize fragments with more ones (descending order of ones)
    if (A.ones !== B.ones) {
        // If B.ones > A.ones, B should come first (positive result means A > B in standard sort, so we invert it)
        return B.ones - A.ones;
    }
    // 2. If ones are equal, prioritize fragments with fewer zeros (ascending order of zeros)
    return A.zeros - B.zeros;
}

