    const fragments: Fragment[] = [];
    for (let i = 0; i < N; i++) {
        fragments.push({ ones: nums1[i], zeros: nums0[i] });
    }

    // 2. Sort the fragments using the custom comparator
    fragments.sort(compareFragments);

    // 3. Calculate the resulting value modulo MOD by simulating bit appending
    let result = 0;

    for (const fragment of fragments) {
        const o = fragment.ones;
        const z = fragment.zeros;

