                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            exp = Math.floor(exp / 2);
        }
        return res;
    };

    // Structure to hold segment info
    type Segment = {
        k: number; // nums1[i] (count of 1s)
        z: number; // nums0[i] (count of 0s)
        L: number; // Total length k + z
    };

    const segments: Segment[] = [];
    let totalLength = 0;

    for (let i = 0; i < nums1.length; i++) {
        const k = nums1[i];
        const z = nums0[i];
        const L = k + z;
        segments.push({ k, z, L });
        totalLength += L;
    }

    // Custom comparison function for sorting: 
    // Returns negative if i should come before j (i > j in our priority sense)
    // Returns positive if j should come before i (i < j in our priority sense)
    segments.sort((i, j) => {
        const ki = i.k, zi = i.z, kj = j.k, zj = j.z;

        // Handle segments of all zeros (k=0). They must go last.
        if (ki === 0 && kj === 0) return 0;
        if (ki === 0) return 1;  // i goes after j (positive return)
        if (kj === 0) return -1; // j goes after i (negative return)

        // Core comparison logic based on S_i S_j vs S_j S_i

        if (ki === kj) {
            // Rule 1: k_i = k_j. Prefer smaller z (fewer trailing zeros).
            return zi - zj; 
        } else if (ki > kj) {
            // Rule 2: k_i > k_j. 
            if (zj > 0) {
                // 2a. z_j > 0: i > j (i comes first)
                return -1; 
            } else {
                // 2b. z_j = 0: j > i (j comes first)
                return 1;
            }
        } else { // ki < kj
            // Rule 3: k_i < k_j.
            if (zi > 0) {
                // 3a. z_i > 0: j > i (j comes first)
                return 1;
            } else {
                // 3b. z_i = 0: i > j (i comes first)
                return -1;
            }
        }
    });

