        const k = segment.k;
        const z = segment.z;
        const L = segment.L;

        // Calculate V(S_i) = (2^k - 1) * 2^z mod M

        // Term 1: 2^k - 1
        let term1_pow_k = power(2, k, MOD);
        let term1 = (term1_pow_k - 1 + MOD) % MOD;

        // Term 2: 2^z
        let term2_pow_z = power(2, z, MOD);

        // Value of the segment itself V(S_i) mod M
        let segmentValue = (term1 * term2_pow_z) % MOD;

        // Calculate the exponent E for the positional weight: E = TotalLength - PrefixLength - SegmentLength
        const exponent = totalLength - prefixLength - L;

        // Positional weight: 2^E mod M
        let weight = power(2, exponent, MOD);

        // Contribution = segmentValue * weight mod M
        let contribution = (segmentValue * weight) % MOD;

        // Accumulate result
        result = (result + contribution) % MOD;

        // Update prefix length
        prefixLength += L;
    }

    return result;
